CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_dep_m_interest_paid() RETURNS trigger AS $BODY$
BEGIN
  if (pka.auto_seqno) then
    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
      select max(seq_no) into STRICT NEW.seq_no
      from sc_dep_m_interest_paid
      where (deposit_account_no = NEW.deposit_account_no);
      NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
    end if;
  end if;

  if coalesce(NEW.deposit_type_code::text, '') = '' then
    select deposit_type_code into STRICT NEW.deposit_type_code 
    from sc_dep_m_creditor 
    where deposit_account_no = NEW.deposit_account_no;
  end if;

  if (coalesce(OLD.deposit_account_no::text, '') = '' and (NEW.deposit_account_no IS NOT NULL AND NEW.deposit_account_no::text <> '')) then
    if (pka.auto_entry) then 
      NEW.working_day := pka_dep.fp_deposit_date();
      NEW.officer_id := trim(both current_setting('app.login_id', true));
      NEW.branch_id := trim(both current_setting('app.login_br', true));
    end if;
  end if;

  if coalesce(NEW.interest_arrear::text, '') = '' then NEW.interest_arrear :=0;end if;

  --if trim(:new.client_id) is null then :new.client_id := trim(pka_com_login.login_pc);end if;
RETURN NEW;
end
